#!/usr/bin/env node
/**
 * Audit channels using the local Streamline server proxy (provider session must be warm).
 * Reads catalog-export.json generated by export-catalog-slices.js
 */

const fs = require("fs");
const path = require("path");

const root = path.resolve(__dirname, "..");
const catalogPath = path.join(root, "catalog-export.json");
const outJson = path.join(root, "channel-audit-results.json");
const outTxt = path.join(root, "channel-audit-failed.txt");
const proxyBase = process.env.AUDIT_PROXY_BASE || "http://127.0.0.1:4202";
const concurrency = Number(process.env.AUDIT_CONCURRENCY || 16);
const timeoutMs = Number(process.env.AUDIT_TIMEOUT_MS || 7000);

const ppvCategoryRe = /pay\s*per\s*view|\bppv\b|i\s*ppv|live\s*events?/i;
const ppvNameRe = /pay\s*per\s*view|\bppv\b/i;

function isPpv(category, name) {
  return ppvCategoryRe.test(category || "") || ppvNameRe.test(name || "");
}

async function testProxyStream(streamId) {
  const url = `${proxyBase}/api/stream/live/${encodeURIComponent(streamId)}.m3u8`;
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const res = await fetch(url, {
      signal: controller.signal,
      headers: { "User-Agent": "StreamlineBluTV-Audit/1.0" }
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const body = await res.text();
    if (!body.includes("#EXTM3U")) throw new Error("Invalid playlist");
    return true;
  } finally {
    clearTimeout(timer);
  }
}

async function runPool(items, worker, limit) {
  const results = new Array(items.length);
  let index = 0;
  async function next() {
    while (index < items.length) {
      const i = index++;
      results[i] = await worker(items[i], i);
      if ((i + 1) % 200 === 0 || i + 1 === items.length) {
        process.stderr.write(`\rChecked ${i + 1}/${items.length}...`);
      }
    }
  }
  await Promise.all(Array.from({ length: limit }, () => next()));
  process.stderr.write("\n");
  return results;
}

async function main() {
  if (!fs.existsSync(catalogPath)) {
    throw new Error(`Missing ${catalogPath}. Run node server/export-catalog-slices.js first.`);
  }
  const allChannels = JSON.parse(fs.readFileSync(catalogPath, "utf8"));
  const skippedPpv = [];
  const channels = allChannels.filter((ch) => {
    if (isPpv(ch.category, ch.name)) {
      skippedPpv.push(ch);
      return false;
    }
    return true;
  });

  console.log(`Auditing ${channels.length} channels via ${proxyBase} (${skippedPpv.length} PPV skipped)...`);

  const results = await runPool(
    channels,
    async (ch) => {
      try {
        await testProxyStream(ch.streamId);
        return { ...ch, status: "ok" };
      } catch (error) {
        return { ...ch, status: "failed", error: error.message || String(error) };
      }
    },
    concurrency
  );

  const failed = results.filter((r) => r.status !== "ok");
  const payload = {
    auditedAt: new Date().toISOString(),
    proxyBase,
    totalAudited: channels.length,
    ppvSkipped: skippedPpv.length,
    working: results.length - failed.length,
    failed: failed.length,
    failedChannels: failed.sort((a, b) => String(a.category).localeCompare(String(b.category)) || String(a.name).localeCompare(String(b.name)))
  };

  fs.writeFileSync(outJson, JSON.stringify(payload, null, 2));
  fs.writeFileSync(
    outTxt,
    failed.map((ch) => `${ch.category} | ${ch.name} | streamId=${ch.streamId} | ${ch.error}`).join("\n") + (failed.length ? "\n" : "")
  );

  console.log(`Working: ${payload.working}`);
  console.log(`Failed: ${payload.failed}`);
  console.log(`Wrote ${outTxt}`);
}

main().catch((error) => {
  console.error(error.message || error);
  process.exit(1);
});
